  "TNR57_2_03": ["Numără înapoi: 10, 9, 8, 7, ?", "Scădem cu 1 de fiecare dată.", ["5", "8", "6", "9"], "Numărăm înapoi: 10, 9, 8, 7, 6. Următorul număr este 6."],
  "TNR57_2_04": ["Numără din 5 în 5: 10, 15, 20, 25, ?", "Adaugă 5 de fiecare dată. Cât face 25 plus 5?", ["28", "35", "25", "30"], "Numărăm din 5 în 5: 10, 15, 20, 25, 30. Următorul număr este 30."],
  "TNR57_2_05": ["Numără înapoi: 5, 4, 3, 2, ?", "Continuă să scazi cu 1!", ["1", "0", "3", "6"], "Numărăm înapoi: 5, 4, 3, 2, 1. Următorul număr este 1."],
  "TNR57_2_06": ["Numără din 10 în 10: 20, 30, 40, 50, ?", "Adaugă 10 de fiecare dată.", ["55", "60", "70", "65"], "Numărăm din 10 în 10: 20, 30, 40, 50, 60. Următorul număr este 60."],
  "TNR57_2_07": ["Numără înapoi: 8, 7, 6, 5, ?", "Continuă să scazi cu 1!", ["3", "6", "4", "5"], "Numărăm înapoi: 8, 7, 6, 5, 4. Următorul număr este 4."],
  "TNR57_2_08": ["Numără din 5 în 5: 25, 30, 35, 40, ?", "Adaugă 5 de fiecare dată. Cât face 40 plus 5?", ["50", "42", "44", "45"], "Numărăm din 5 în 5: 25, 30, 35, 40, 45. Următorul număr este 45."],
  "TNR57_2_09": ["Numără din 10 în 10: 30, 40, 50, 60, ?", "Adaugă 10 de fiecare dată. Cât face 60 plus 10?", ["70", "65", "80", "75"], "Numărăm din 10 în 10: 30, 40, 50, 60, 70. Următorul număr este 70."],
  "TNR57_2_10": ["Numără înapoi din 2 în 2: 20, 18, 16, 14, ?", "Scade 2 de fiecare dată.", ["13", "12", "10", "15"], "Numărăm înapoi din 2 în 2: 20, 18, 16, 14, 12. Următorul număr este 12."],
  "TNR57_2_11": ["Numără din 5 în 5: 30, 35, 40, 45, ?", "Adaugă 5 de fiecare dată.", ["55", "48", "50", "52"], "Numărăm din 5 în 5: 30, 35, 40, 45, 50. Următorul număr este 50."],
  "TNR57_2_12": ["Numără înapoi: 15, 14, 13, 12, ?", "Continuă să scazi cu 1!", ["10", "13", "14", "11"], "Numărăm înapoi: 15, 14, 13, 12, 11. Următorul număr este 11."],
  "TNR57_2_13": ["Numără din 10 în 10: 50, 60, 70, 80, ?", "Adaugă 10 de fiecare dată.", ["90", "85", "100", "95"], "Numărăm din 10 în 10: 50, 60, 70, 80, 90. Următorul număr este 90."],
  "TNR57_2_14": ["Numără înapoi din 2 în 2: 10, 8, 6, 4, ?", "Scade 2 de fiecare dată.", ["3", "2", "1", "0"], "Numărăm înapoi din 2 în 2: 10, 8, 6, 4, 2. Următorul număr este 2."],
  "TNR57_2_15": ["Ce număr lipsește? 5, 10, ?, 20, 25", "Numărăm din 5 în 5. Ce este între 10 și 20?", ["12", "18", "15", "14"], "Numărând din 5 în 5: 5, 10, 15, 20, 25. Numărul lipsă este 15."],
  "TNR57_2_16": ["Numără din 5 în 5: 40, 45, 50, 55, ?", "Adaugă 5 de fiecare dată.", ["58", "65", "55", "60"], "Numărăm din 5 în 5: 40, 45, 50, 55, 60. Următorul număr este 60."],
  "TNR57_2_17": ["Numără înapoi din 10 în 10: 30, 20, 10, ?", "Scade 10 de fiecare dată.", ["0", "5", "15", "10"], "Numărăm înapoi din 10 în 10: 30, 20, 10, 0. Următorul număr este 0."],
  "TNR57_2_18": ["Numără din 10 în 10: 40, 50, 60, 70, ?", "Adaugă 10 de fiecare dată.", ["75", "80", "90", "85"], "Numărăm din 10 în 10: 40, 50, 60, 70, 80. Următorul număr este 80."],
  "TNR57_2_19": ["Ce număr lipsește? 10, 20, 30, ?, 50", "Numărăm din 10 în 10. Ce este între 30 și 50?", ["35", "45", "40", "25"], "Numărând din 10 în 10: 10, 20, 30, 40, 50. Numărul lipsă este 40."],
  "TNR57_2_20": ["Numără înapoi din 5 în 5: 50, 45, 40, 35, ?", "Scade 5 de fiecare dată.", ["25", "32", "34", "30"], "Numărăm înapoi din 5 în 5: 50, 45, 40, 35, 30. Următorul număr este 30."],

