  "TNR57_3_01": ["Numără din 3 în 3: 3, 6, 9, 12, ?", "Adaugă 3 de fiecare dată. Cât face 12 plus 3?", ["15", "13", "14", "16"], "Numărăm din 3 în 3: 3, 6, 9, 12, 15. Următorul număr este 15."],
  "TNR57_3_02": ["Numără din 3 în 3: 6, 9, 12, 15, ?", "Adaugă 3 de fiecare dată.", ["16", "18", "17", "19"], "Numărăm din 3 în 3: 6, 9, 12, 15, 18. Următorul număr este 18."],
  "TNR57_3_03": ["Ce număr lipsește? 2, 4, ?, 8, 10, 12", "Numărăm din 2 în 2. Ce este între 4 și 8?", ["5", "7", "6", "9"], "Numărând din 2 în 2: 2, 4, 6, 8, 10, 12. Numărul lipsă este 6."],
