  "TNR57_3_09": ["Numără înapoi din 3 în 3: 15, 12, 9, 6, ?", "Scade 3 de fiecare dată.", ["3", "4", "5", "2"], "Numărăm înapoi din 3 în 3: 15, 12, 9, 6, 3. Următorul număr este 3."],
  "TNR57_3_10": ["Numără din 4 în 4: 4, 8, 12, 16, ?", "Adaugă 4 de fiecare dată. Cât face 16 plus 4?", ["18", "20", "22", "24"], "Numărăm din 4 în 4: 4, 8, 12, 16, 20. Următorul număr este 20."],
  "TNR57_3_11": ["Ce număr lipsește? 10, ?, 30, 40, 50", "Numărăm din 10 în 10. Ce este între 10 și 30?", ["15", "25", "20", "35"], "Numărând din 10 în 10: 10, 20, 30, 40, 50. Numărul lipsă este 20."],
  "TNR57_3_12": ["Numără înapoi din 5 în 5: 25, 20, 15, 10, ?", "Scade 5 de fiecare dată.", ["0", "8", "6", "5"], "Numărăm înapoi din 5 în 5: 25, 20, 15, 10, 5. Următorul număr este 5."],
  "TNR57_3_13": ["Numără din 3 în 3: 15, 18, 21, 24, ?", "Adaugă 3 de fiecare dată. Cât face 24 plus 3?", ["27", "25", "26", "28"], "Numărăm din 3 în 3: 15, 18, 21, 24, 27. Următorul număr este 27."],
  "TNR57_3_14": ["Ce număr lipsește? 1, 3, 5, ?, 9, 11", "Numărăm din 2 în 2 (numere impare). Ce este între 5 și 9?", ["6", "7", "8", "10"], "Numărând din 2 în 2: 1, 3, 5, 7, 9, 11. Numărul lipsă este 7."],
  "TNR57_3_15": ["Numără înapoi din 3 în 3: 21, 18, 15, 12, ?", "Scade 3 de fiecare dată.", ["10", "11", "9", "8"], "Numărăm înapoi din 3 în 3: 21, 18, 15, 12, 9. Următorul număr este 9."],
  "TNR57_3_16": ["Numără din 4 în 4: 8, 12, 16, 20, ?", "Adaugă 4 de fiecare dată. Cât face 20 plus 4?", ["22", "26", "28", "24"], "Numărăm din 4 în 4: 8, 12, 16, 20, 24. Următorul număr este 24."],
  "TNR57_3_17": ["Ce urmează? 2, 5, 8, 11, ?", "Adăugăm 3 de fiecare dată.", ["14", "12", "13", "15"], "Adăugăm 3 de fiecare dată: 2, 5, 8, 11, 14. Următorul număr este 14."],
